const sources = $('Set RSS Sources').all();
return $input.all().map((item, i) => ({
  json: {
    source_name: sources[i].json.source_name,
    language: sources[i].json.language,
    xmlData: item.json.data || ''
  }
}));

const crypto = require('crypto');
const REGION_KEYWORDS = [
  'cameroon','cameroun','yaoundé','yaounde','douala','biya','ambazonia',
  'anglophone','southern cameroons','nord-ouest','sud-ouest','northwest','southwest',
  'chad','tchad','ndjamena',"n'djamena",
  'central african republic','centrafrique','bangui','car ',
  'congo','brazzaville','kinshasa','drc','rdc',
  'gabon','libreville','bongo',
  'nigeria','abuja','lagos','buhari','tinubu',
  'afcon','indomitable lions','lions indomptables',"eto'o",'fecafoot',
  'boko haram','lake chad','cemac','eccas'
];
const CAMEROON_SOURCES = [
  '237online','237actu','camerounactuel','stopblablacam','camer_be',
  'journal_du_cameroun','courrier_du_cameroun','quatrieme_pouvoir',
  'lebledparle','teleasu','guardian_post','sun_newspaper',
  'echosante','lejour','allafrica_cameroon','foot_africa'
];
function getTagContent(block, tag) {
  const cdataOpen = '<'+tag+'><![CDATA[';
  const cdataClose = ']]></'+tag+'>';
  let si = block.indexOf(cdataOpen);
  if (si !== -1) { const ei = block.indexOf(cdataClose,si); if (ei !== -1) return block.slice(si+cdataOpen.length,ei).trim(); }
  const open = '<'+tag+'>'; const close = '</'+tag+'>';
  si = block.indexOf(open);
  if (si !== -1) { const ei = block.indexOf(close,si); if (ei !== -1) return block.slice(si+open.length,ei).trim(); }
  return '';
}
function getAttrValue(block, attr) {
  const dqSearch = attr+'="'; let si = block.indexOf(dqSearch);
  if (si !== -1) { const start = si+dqSearch.length; const end = block.indexOf('"',start); if (end !== -1) return block.slice(start,end); }
  return '';
}
function getImageUrl(block) {
  for (const tag of ['<media:content ','<enclosure ']) {
    const idx = block.indexOf(tag); if (idx !== -1) { const end = block.indexOf('>',idx); if (end !== -1) { const url = getAttrValue(block.slice(idx,end),'url'); if (url) return url; } }
  }
  return null;
}
function isRelevant(title, desc) {
  const text = (title+' '+desc).toLowerCase();
  return REGION_KEYWORDS.some(kw => text.includes(kw));
}
const rows = [];
for (const item of $input.all()) {
  const source_name = item.json.source_name||'unknown';
  const language = item.json.language||'en';
  const xmlText = item.json.xmlData||'';
  if (!xmlText) continue;
  const parts = xmlText.split('<item>');
  for (let i = 1; i < parts.length; i++) {
    const endIdx = parts[i].indexOf('</item>'); if (endIdx === -1) continue;
    const block = parts[i].substring(0,endIdx);
    const title = getTagContent(block,'title');
    let link = getTagContent(block,'link'); if (!link) link = getTagContent(block,'guid');
    const description = getTagContent(block,'description');
    if (!title||!link) continue;
    if (!CAMEROON_SOURCES.includes(source_name) && !isRelevant(title,description)) continue;
    const hashInput = (title+link).toLowerCase().replace(/\s+/g,'');
    const content_hash = require('crypto').createHash('sha256').update(hashInput).digest('hex');
    rows.push({ source_name, source_url: link, content_hash, raw_title: title.substring(0,500), raw_body: description.substring(0,5000), raw_image_url: getImageUrl(block), language, status: 'pending' });
  }
}
return rows.map(r => ({ json: r }));
